INSERT INTO Therapists(id, name, certified, image_Url, bio, location, url) VALUES
(1, 'Kezzia Quintyne-Hilaire', 'LMHC, CASAC, Counselor', '', 'Your feelings are valid! As a Licensed Mental Health Counselor and a Black therapist in NYC, I understand the value of receiving quality therapy services. My practice is dedicated to helping women of color keep their crowns on straight. I specialize in trauma, womens issues, and anxiety. My primary therapeutic focus is Eye Movement Desensitization and Reprocessing (EMDR), which uses bilateral stimulation to help replace traumatic memories. Healing occurs through various approaches, so I also use multiple therapies to help my clients reduce depression, anxiety, work stress, and emotional distress.', 'Brooklyn','https://www.kqhcounseling.com/contact-black-female-therapist-nyc'),
(2, 'Keanu M. Jackson', 'Clinical Social Work/Therapist, LCSW', '', 'In our sessions, we will delve into the complex tapestry of your relationships, exploring the dynamics of intimacy and connection with honesty and vulnerability. From navigating communication challenges to deepening emotional intimacy, I provide practical tools and insightful guidance for you to foster healthier, more fulfilling connections with others and yourself. What excites me most about this work is being able to share space with those within my own communities. As a kinky, queer, Black therapist I recognize that what we need is the opportunity to expand our horizons in an effort to dive deeper into the richness of who we are.', 'Brooklyn', 'https://www.keanumjackson.com'),
(3, 'Queen Ravenden', 'Art Therapist, R-DMT, LCAT', '',	'Greetings and peace to you, divine being. I am a black, caribbean american, creative arts therapist providing safe, affirming, uplifting, and holistic healing. My therapeutic style uses a strength-based approach while incorporating creative art therapy techniques and catering to the balance & overall wellbeing of the mind, body, & soul. I work with individuals to overcome low self-esteem, self-doubt, anxiety, past traumas, and depression using creative arts therapy.', 'Brooklyn', 'https://www.mindbodysoulvirtualwellnesscenter.com'),
(4, 'Chelsea Thornton', 'Licensed Master Social Work, LMSW', '', 'I’m passionate in analyzing interpersonal connections through a multicultural lens. I frequently utilize CBT, EFT (Emotionally Focused Therapy), ARA (the Ackerman Relational Approach), and mindfulness techniques as we learn and embrace the many overlapping identities that exist within you. I provide services to children, teens, adults, couples, and families.', 'Brooklyn', 'https://www.zocdoc.com/professional/chelsea-thornton-lmsw-480442'),
(5, 'The Healing Collective', 'Clinical Social Work/Therapist, LCSW','', 'The Healing Collective is a New York-based therapeutic group practice that centers the healing of Black folks, Indigenous folks, and non-Black folks of color. We offer telehealth services to individuals (youth and adults), couples, and families throughout New York and New Jersey. We also offer coaching services throughout the United States. The Healing Collective believes that every being is worthy of healing and that our healing comes from within. We’d be honored if you chose us for your healing journey.', 'Brooklyn', 'https://www.thehealingcollectivepractice.com'),
(6, 'Shani Graves', 'Counselor, LMHC', '', 'Maybe its been two months or two years, but it has not been easy. Whether its your personal life, work life, familial, platonic, or romantic relationships. You may have begun to feel overwhelmed,annoyed, stressed, lonely and even depressed. You compare yourself to others and wonder why your life is not a reflection of the work you have put into it or how you imagined it would be. If any of these feelings have taken root in your life, contact me and my team today. Our role at SG Wellness is to create a space for Black, Latinx and People of Color to begin exploring patterns and work towards change. Together we can work to get you out of the haze, reduce pressure and set boundaries for yourself and others.', 'Brooklyn', 'https://sgcounselingnyc.com'),
(7, 'Tanner Kaleb Williams', 'Licensed Master Social Worker, LMSW', '', 'Hello there :) I am Tanner (he/him) a Black, queer, art and creativity lover based in Brooklyn, NY on occupied Lenape land. If you are searching for a therapist who truly listens and collaborates rather than just gives advice and diagnoses, I would be honored to connect with you. I focus on embracing radical acceptance, fostering community based care, and moving beyond labeling our experiences. If you are in need of a safe space to be your authentic self, we might be a perfect match. Please reach out! I am eager to hear about what is bringing you to therapy.', 'Manhattan', 'https://www.inclusivetherapists.com/new-york/brooklyn/tanner-williams'),
(8, 'Cloricea Brooks', 'Counselor, MA, LMHC, CASAC-T', '', 'Everyday we tell ourselves stories through our thoughts. These stories stem from our lived experiences, which are inseparable from our cultural identities. Life challenges like job stress, relationship issues, trauma, and grief can lead to stories that highlight fear, anger, mistrust, and sadness, resulting in detachment and difficulty feeling joy. I believe that restoring genuine connections with yourself and others is a powerful antidote. Together we will explore cognitive and behavioral interventions to change what you can, while intentionally accepting the unchangeable in a compassionate space.', 'Manhattan', 'https://headway.co/providers/cloricea-brooks'),
(9, 'Dr. Gary Dillon', 'Psychologist, PhD', '', 'Frustrated, stuck, or unfulfilled in an area of your life? You are not alone. Amid a global pandemic, along with the current social and political climate, knowing how to begin healing can be a challenge. Life is complicated and it can be difficult to reach out to gain the support and encouragement that you need to succeed. But don’t worry, I’ll be your ally on this journey - supporting and helping you along the way. As a Black male therapist in NYC, I specialize in working with individuals & couples, who at times feel powerless and are often marginalized - including immigrants, people of color, and members of the LGBTQIA+ community.', 'Manhattan', 'https://www.allypsychotherapy.com'),
(10, 'Racine Renee Henry', 'Marriage & Family Therapist, PhD, LMFT', '', 'The word Sankofa means "one must go back in order to move forward". The idea is that in order to move forward into our highest potential, we must use the best of what was in our past. As a relational therapist who primarily works from a Solution-Focused approach, the word Sankofa reflects my belief that learning from our experiences in the past can contribute to healing in the present and future. I believe we are all capable of change through an effective solution. I have experience bringing about the changes that will lead to a healthier and happier life. I specialize in treating couples from marginalized and minority groups. I have done extensive research and training on issues commonly experienced by women of all backgrounds, within the Black community and within Black romantic relationships.', 'Staten Island', 'https://www.sankofatherapynyc.com'),
(11, 'Amira R Martin', 'Clinical Social Work/Therapist, LCSW-R', '', 'I am here to provide you with warm and compassionate support as you navigate lifes challenges. Your journey is unique, and I want you to feel genuinely heard and understood. If you are facing issues like Depression, Anxiety, difficult relationships and work-related struggles, I am here to help you navigate and recover from these challenges. My commitment is to create a safe and supportive space for your healing. Together, we will address your struggles and challenges while fostering your personal growth and resilience. You can achieve emotional well-being, navigate life transitions, and ultimately lead a more fulfilling life.', 'Brooklyn', 'https://www.amiraforher.com'),
(12, 'Vanessa A. Williams', 'Counselor, LMHC', '', '"There is no greater agony than bearing the untold story inside you." - Maya Angelou. Each person’s story shapes them and a burden to carry alone that is relieved when met with empathy. I consider it an honor to be present with clients as they share their untold story, gain greater self-knowledge, and manifest the story that is yet to come. I come from a place of curiosity and non-judgement around each individual’s lived experience. I hope to create a warm, accepting space where you can be your authentic self, feel safe to express your uncensored thoughts and share both laughter and tears.', 'Brooklyn', 'https://rootsandbranchestherapy.nyc/vanessa-williams/'),
(13, 'Dwayne James', 'Clinical Social Work/Therapist, MSW, LCSW', '' ,'I say seeking therapy is nothing close to a sign of weakness but the biggest sign of strength you can possibly have. My name is Dwayne James, and I am a Black male clinician. With over five years of clinical therapeutic experience, my passion for social-emotional support continues to shine through with every client interaction. My overall therapeutic goal is to ensure folks get the essential tools to add to their tool kit in times of need while also providing the utmost support for their social and emotional needs. My work is rooted in cultural sensitivity and recognizes that clients are experts in their own experiences.', 'Brooklyn', 'https://headway.co/providers/dwayne-james?utm_source=pem&utm_medium=direct_link&utm_campaign=94657'),
(14, 'Uzoma Chibundu', 'Clinical Social Work/Therapist, LMSW', '','My therapeutic approach is collaborative, warm, authentic and holistic. I believe the client is the expert of their experiences and my purpose is to assist them in their journey toward healing. I help clients through an array of talk therapy, story telling and treatment-centered homework. I operate from a relational, intersectional, and anti-oppressive lens. Everyone has their own therapeutic journey, and who we bring on this journey is up to us. Ones journey towards healing can be a culmination of tough conversations, laughter, and tears. My hope is that we all find people to accompany us on our therapeutic journey. Lets schedule a free consultation to see we would be a good fit.', 'Brooklyn', 'https://www.psychologytoday.com/us/therapists/uzoma-chibundu-brooklyn-ny/1051407');
